import React from 'react';
import {StyleSheet, Text, View} from 'react-native';
import {useQuery} from '@tanstack/react-query';
import {FeatureTodoCard} from '../../components/FeatureTodoCard';
import {Screen} from '../../components/Screen';
import {useAuth} from '../../features/auth/AuthProvider';
import {mobileApi} from '../../lib/api/mobileApi';
import {useTheme} from '../../theme/ThemeProvider';

export function FreedomWallScreen() {
  const {colors} = useTheme();
  const {session} = useAuth();
  const token = session?.access_token;

  const currentWeekQuery = useQuery({
    queryKey: ['freedom-current-week'],
    queryFn: () => mobileApi.getCurrentFreedomWallWeek(token),
  });

  const weeksQuery = useQuery({
    queryKey: ['freedom-weeks'],
    queryFn: () => mobileApi.getFreedomWallWeeks(8, token),
  });

  const activeWeekId = currentWeekQuery.data?.data?.id;

  const itemsQuery = useQuery({
    queryKey: ['freedom-items', activeWeekId],
    enabled: Boolean(activeWeekId),
    queryFn: () => mobileApi.getFreedomWallItems(activeWeekId ?? '', {limit: 200}, token),
  });

  return (
    <Screen>
      <Text style={[styles.title, {color: colors.textPrimary}]}>Freedom Wall</Text>
      <FeatureTodoCard
        title="Collaborative wall route wired"
        description="Week selection and item APIs are mapped for native implementation. Gesture board and minimap interactions are the next delivery unit."
      />
      <View
        style={[
          styles.card,
          {backgroundColor: colors.bgElevated, borderColor: colors.borderLight},
        ]}>
        <Text style={[styles.cardTitle, {color: colors.textPrimary}]}>Data snapshot</Text>
        <Text style={[styles.cardText, {color: colors.textMuted}]}>
          {currentWeekQuery.isLoading
            ? 'Loading current week...'
            : `Current week id: ${activeWeekId || 'Unavailable'}`}
        </Text>
        <Text style={[styles.cardText, {color: colors.textMuted}]}>
          {weeksQuery.isLoading
            ? 'Loading week list...'
            : `Known weeks: ${weeksQuery.data?.data?.length ?? 0}`}
        </Text>
        <Text style={[styles.cardText, {color: colors.textMuted}]}>
          {itemsQuery.isLoading
            ? 'Loading wall items...'
            : `Items in current week: ${itemsQuery.data?.data?.length ?? 0}`}
        </Text>
      </View>
    </Screen>
  );
}

const styles = StyleSheet.create({
  title: {
    fontSize: 24,
    fontWeight: '800',
  },
  card: {
    borderWidth: 1,
    borderRadius: 12,
    padding: 12,
    gap: 6,
  },
  cardTitle: {
    fontWeight: '700',
    fontSize: 15,
  },
  cardText: {
    fontSize: 14,
  },
});

