  1→const DEFAULT_CANVAS_DOC = {
  2→    version: 1,
  3→    meta: {
  4→        aspectRatio: '1:1',
  5→        gridEnabled: true,
  6→        theme: 'light'
  7→    },
  8→    snippets: [],
