291→export const getCanvasGallery = async(userId, limit = 36, sort = 'hottest', cursor = null) => {
292→    const parsedLimit = Number(limit);
293→    if(Number.isNaN(parsedLimit) || parsedLimit < 1 || parsedLimit > 72){
294→        throw new Error('limit should be an integer between 1 and 72');
295→    }
296→
297→    const normalizedSort = typeof sort === 'string' && sort.trim().toLowerCase() === 'newest'
298→        ? 'newest'
299→        : 'hottest';
300→
301→    let url = `${BASE_URL}/journals/canvas/gallery?limit=${parsedLimit}&sort=${encodeURIComponent(normalizedSort)}`;
302→    if(userId){
303→        url += `&userId=${encodeURIComponent(userId)}`;
304→    }
305→    if(cursor){
306→        url += `&cursor=${encodeURIComponent(cursor)}`;
307→    }
308→
309→    const response = await apiRequest(url, {
310→        method: 'GET'
311→    });
312→
313→    if(!response.ok){
314→        const error = await response.json().catch(() => ({}));
315→        throw new Error(error?.error || 'failed to fetch canvas gallery');
316→    }
317→
318→    return await response.json();
319→}
