 3→export const extractPlainText = (rawContent: string | null | undefined): string => {
 4→  if (!rawContent) return '';
 5→  try {
 6→    const parsed = JSON.parse(rawContent) as {
 7→      root?: {children?: Array<{children?: Array<{text?: string}>}>};
 8→    };
 9→    const parts: string[] = [];
10→    parsed.root?.children?.forEach(node => {
11→      node.children?.forEach(child => {
12→        if (child.text) parts.push(child.text);
13→      });
14→    });
15→    return parts.join(' ').replace(/\s+/g, ' ').trim();
16→  } catch {
17→    return rawContent.replace(/\s+/g, ' ').trim();
18→  }
19→};
20→
21→export const extractBannerImage = (
22→  rawContent: string | null | undefined,
23→  images?: string | string[] | null,
24→): string | null => {
25→  if (images) {
26→    if (typeof images === 'string') {
27→      try {
28→        const parsed = JSON.parse(images);
29→        if (Array.isArray(parsed) && parsed.length > 0) return parsed[0];
30→      } catch {
31→        if (images.startsWith('http')) return images;
32→      }
33→    }
34→    if (Array.isArray(images) && images.length > 0) return images[0];
35→  }
36→  if (!rawContent) return null;
37→  try {
38→    const parsed = JSON.parse(rawContent);
39→    const findImage = (node: any): string | null => {
40→      if (node.type === 'image' && node.src) return node.src;
41→      if (node.children) {
42→        for (const child of node.children) {
43→          const found = findImage(child);
44→          if (found) return found;
45→        }
46→      }
47→      return null;
48→    };
49→    return findImage(parsed.root ?? parsed);
50→  } catch {
51→    return null;
52→  }
53→};
54→
55→export const normalizeCount = (value: unknown): number => {
56→  const parsed = Number(value);
57→  return Number.isFinite(parsed) && parsed >= 0 ? parsed : 0;
58→};
59→
60→export const resolveCount = (
61→  aggregate: Array<{count?: number}> | undefined,
62→  fallback?: number,
63→): number => {
64→  if (Array.isArray(aggregate) && aggregate.length > 0)
65→    return normalizeCount(aggregate[0]?.count);
66→  return normalizeCount(fallback);
67→};
68→
69→export const getNextCursor = (
70→  page: CursorPage<JournalItem>,
71→  pageSize: number,
72→): string | undefined => {
73→  if (page.nextCursor) return page.nextCursor;
74→  if (page.hasMore && page.data.length > 0)
75→    return page.data[page.data.length - 1]?.created_at ?? undefined;
76→  if (page.data.length >= pageSize)
77→    return page.data[page.data.length - 1]?.created_at ?? undefined;
78→  return undefined;
79→};
