247→  async saveJournal(token: string, payload: { title: string; plainText: string; html?: string }): Promise<{ message?: string }> {
248→    const formData = new FormData();
249→
250→    const lexicalPayload = {
251→      root: {
252→        children: [
253→          {
254→            type: 'paragraph',
255→            children: [
256→              {
257→                type: 'text',
258→                text: payload.plainText,
259→                detail: 0,
260→                format: 0,
261→                mode: 'normal',
262→                style: '',
263→                version: 1,
264→              },
265→            ],
266→            direction: null,
267→            format: '',
268→            indent: 0,
269→            version: 1,
270→          },
271→        ],
272→        direction: null,
273→        format: '',
274→        indent: 0,
275→        type: 'root',
276→        version: 1,
277→      },
278→    };
279→
280→    formData.append('title', payload.title);
281→    formData.append('content', JSON.stringify(lexicalPayload));
282→    formData.append('post_type', 'text');
283→
284→    return apiRequest<{ message?: string }>('/save-journal', {
285→      method: 'POST',
286→      headers: {
287→        ...authHeaders(token),
288→      },
289→      body: formData,
290→      timeoutMs: 30000,
291→      retries: 0,
292→    });
293→  },
294→};
