 16→function getInitials(name?: string): string {
 17→  if (!name) return '?';
 18→  const parts = name.trim().split(/\s+/);
 19→  if (parts.length === 1) return parts[0][0]?.toUpperCase() ?? '?';
 20→  return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
 21→}
